+    #[test]
+    fn test_degraded_mode_triggers_at_f_failures() {
+        let policy = QuorumPolicy::new(ZoneId::work(), 5, 1).with_degraded_mode(3);
+
+        // Full capacity: not degraded
+        assert!(!policy.is_degraded(5));
+
+        // One failure (at f): degraded
