+    let mut set = SignatureSet::new();
+    for i in 0..node_count {
+        set.add(NodeSignature::new(
+            NodeId::new(format!("node-{i:02}")),
+            [i as u8; 64],
+            1704067200 + i as u64, // 2024-01-01 00:00:00 + offset
+        ));
+    }
+    set
+}
